            System.exit(1);
        }
    }

    private static void processDirectory(String directoryPath) throws IOException {
        Path directory = Paths.get(directoryPath);
        if (!Files.exists(directory)) {
            System.err.println("Directory does not exist: " + directoryPath);
            return;
